import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import './Header.css';

const Header = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  // Calculate user progress based on completed actions
  const calculateProgress = () => {
    if (!user) return 0;
    
    let completedActions = 0;
    const totalActions = 4; // Quiz, Profile, Courses, Mentors
    
    // Check if user has taken quiz
    if (user.quizResults && user.quizResults.length > 0) {
      completedActions++;
    }
    
    // Check if user has completed profile
    if (user.profile && (
      user.profile.skills?.length > 0 || 
      user.profile.interests?.length > 0 ||
      user.profile.bio
    )) {
      completedActions++;
    }
    
    // Check if user has explored courses (we'll track this via localStorage for now)
    const hasExploredCourses = localStorage.getItem('hasExploredCourses');
    if (hasExploredCourses) {
      completedActions++;
    }
    
    // Check if user has explored mentors
    const hasExploredMentors = localStorage.getItem('hasExploredMentors');
    if (hasExploredMentors) {
      completedActions++;
    }
    
    return Math.round((completedActions / totalActions) * 100);
  };

  const progress = calculateProgress();

  return (
    <header className="header">
      <div className="container">
        <Link to={user ? "/dashboard" : "/"} className="logo">
          <span className="logo-icon">🧠</span>
          MindMatch
        </Link>
        
        <nav className="nav">
          {user ? (
            <>
              <Link to="/dashboard">Dashboard</Link>
              <Link to="/quiz">Career Quiz</Link>
              <Link to="/profile">Profile</Link>
              <Link to="/courses">Courses</Link>
              <Link to="/mentors">Mentors</Link>
              
              {/* Progress Indicator */}
              <div className="progress-indicator">
                <Link to="/progress" className="progress-link">
                  <div className="progress-circle">
                    <svg width="24" height="24" viewBox="0 0 24 24">
                      <circle
                        cx="12"
                        cy="12"
                        r="10"
                        stroke="#e2e8f0"
                        strokeWidth="2"
                        fill="none"
                      />
                      <circle
                        cx="12"
                        cy="12"
                        r="10"
                        stroke="#667eea"
                        strokeWidth="2"
                        fill="none"
                        strokeLinecap="round"
                        strokeDasharray="62.8"
                        strokeDashoffset={62.8 - (62.8 * progress) / 100}
                        transform="rotate(-90 12 12)"
                      />
                    </svg>
                    <span className="progress-text">{progress}%</span>
                  </div>
                  <span className="progress-label">Progress</span>
                </Link>
              </div>

              <button onClick={handleLogout} className="logout-btn">
                Logout
              </button>
              <span className="user-welcome">Hello, {user.name}</span>
            </>
          ) : (
            <>
              <Link to="/login">Login</Link>
              <Link to="/signup">Sign Up</Link>
            </>
          )}
        </nav>
      </div>
    </header>
  );
};

export default Header;
